// Paris DispatchTrack Webhook Receiver — Process Payload
// Handles: dispatch, route, dispatch_guide, review events
// Auth: X-Webhook-Secret header validation
// Mirrors logic from beetrack-webhook Supabase edge function (MUSAN/DT)

const SUPABASE_URL = 'https://wfwlcpnkkxxzdvhvvsxb.supabase.co';
const SUPABASE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';
const PARIS_DT_SECRET = '<PARIS_DT_WEBHOOK_SECRET>';
const MUSAN_OPERATOR_ID = '92dc5797-047d-458d-bbdb-63f18c0dd1e7';
const PROVIDER = 'dispatchtrack';
const RETAILER_NAME = 'Paris';
const STATUS_MAP = { 1: 'pending', 2: 'delivered', 3: 'failed', 4: 'partial' };

async function sbFetch(path, method, body, preferHeader) {
  const url = SUPABASE_URL + '/rest/v1/' + path;
  const headers = {
    'apikey': SUPABASE_KEY,
    'Authorization': 'Bearer ' + SUPABASE_KEY,
    'Content-Type': 'application/json'
  };
  if (preferHeader) headers['Prefer'] = preferHeader;
  const opts = { method, headers };
  if (body) opts.body = JSON.stringify(body);
  const res = await fetch(url, opts);
  const text = await res.text();
  try { return JSON.parse(text); } catch (e) { return {}; }
}

// Validate auth
const hdrs = $input.first().json.headers || {};
const incoming = hdrs['x-webhook-secret'] || hdrs['X-Webhook-Secret'] || '';
if (incoming !== PARIS_DT_SECRET) {
  throw new Error('Unauthorized: invalid X-Webhook-Secret');
}

const body = $input.first().json.body || {};
const resource = body.resource;
const event = body.event;
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const filename = (resource || 'unknown') + '-' + (event || 'unknown') + '-' + now.getTime() + '.json';

let result = { resource, event, ok: true };

// Fetch Paris tenant_client_id dynamically by slug
const tcRows = await sbFetch(
  'tenant_clients?slug=eq.paris&operator_id=eq.' + MUSAN_OPERATOR_ID + '&select=id',
  'GET'
);
const PARIS_TENANT_CLIENT_ID = Array.isArray(tcRows) && tcRows.length > 0 ? tcRows[0].id : null;

switch (resource) {
  case 'dispatch': {
    const dispatchId = body.dispatch_id;
    const routeId = body.route_id;
    const identifier = body.identifier;
    const statusCode = body.status;

    if (!dispatchId) { result.skipped = 'no dispatch_id'; break; }
    const status = STATUS_MAP[statusCode];
    if (!status) { result.skipped = 'unknown status: ' + statusCode; break; }

    // Upsert fleet vehicle
    let vehicleId = null;
    if (body.truck_identifier) {
      const vehicles = await sbFetch(
        'fleet_vehicles?on_conflict=operator_id,provider,external_vehicle_id',
        'POST',
        { operator_id: MUSAN_OPERATOR_ID, provider: PROVIDER, external_vehicle_id: body.truck_identifier, vehicle_type: body.truck_type || null, raw_data: {} },
        'resolution=merge-duplicates,return=representation'
      );
      vehicleId = Array.isArray(vehicles) ? ((vehicles[0] && vehicles[0].id) || null) : null;
    }

    // Lookup Paris order by order_number
    let orderId = null;
    if (identifier && PARIS_TENANT_CLIENT_ID) {
      const orders = await sbFetch(
        'orders?order_number=eq.' + encodeURIComponent(identifier) + '&operator_id=eq.' + MUSAN_OPERATOR_ID + '&tenant_client_id=eq.' + PARIS_TENANT_CLIENT_ID + '&select=id&limit=1',
        'GET'
      );
      orderId = Array.isArray(orders) ? ((orders[0] && orders[0].id) || null) : null;
    }

    const substatus = body.substatus || null;
    const failureReason = status === 'failed' && substatus ? substatus : null;

    await sbFetch(
      'dispatches?on_conflict=operator_id,provider,external_dispatch_id',
      'POST',
      {
        operator_id: MUSAN_OPERATOR_ID, provider: PROVIDER,
        external_dispatch_id: String(dispatchId),
        external_route_id: routeId != null ? String(routeId) : null,
        order_id: orderId, vehicle_id: vehicleId, status, substatus,
        substatus_code: body.substatus_code || null,
        planned_sequence: body.position || null,
        estimated_at: body.estimated_at || null,
        arrived_at: body.arrived_at || null,
        completed_at: body.time_of_management || body.arrived_at || null,
        failure_reason: failureReason,
        is_pickup: body.is_pickup || false,
        latitude: body.management_latitude || null,
        longitude: body.management_longitude || null,
        raw_data: body
      },
      'resolution=merge-duplicates,return=representation'
    );

    // Update order status for terminal dispatches
    if (orderId && (status === 'delivered' || status === 'failed' || status === 'partial')) {
      const orderStatus = status === 'delivered' ? 'entregado' : 'cancelado';
      const statusDetail = status === 'delivered'
        ? 'Delivered via DispatchTrack dispatch #' + dispatchId
        : status === 'partial'
        ? 'Partial delivery via DispatchTrack dispatch #' + dispatchId + (substatus ? ' — ' + substatus : '')
        : substatus || 'Failed via DispatchTrack dispatch #' + dispatchId;
      await fetch(SUPABASE_URL + '/rest/v1/orders?id=eq.' + orderId + '&status=neq.entregado', {
        method: 'PATCH',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: orderStatus, status_detail: statusDetail })
      });
    }

    result = Object.assign({}, result, { dispatch_id: dispatchId, status, order_id: orderId });
    break;
  }

  case 'route': {
    const routeIdRaw = body.route;
    if (!routeIdRaw) { result.skipped = 'no route id'; break; }
    const externalRouteId = String(routeIdRaw);
    let routeStatus = 'planned';
    if (body.started && body.ended) routeStatus = 'completed';
    else if (body.started) routeStatus = 'in_progress';

    // Only update routes managed by this system (created via Aureon dispatch module)
    const existingRoutes = await sbFetch(
      'routes?operator_id=eq.' + MUSAN_OPERATOR_ID + '&provider=eq.' + PROVIDER + '&external_route_id=eq.' + externalRouteId + '&deleted_at=is.null&select=id&limit=1',
      'GET'
    );
    const existingRoute = Array.isArray(existingRoutes) ? existingRoutes[0] : null;

    if (!existingRoute) {
      result.skipped = 'route not managed by this system';
      result.route_id = externalRouteId;
      break;
    }

    let vehicleId = null;
    if (body.truck) {
      const vehicles = await sbFetch(
        'fleet_vehicles?on_conflict=operator_id,provider,external_vehicle_id',
        'POST',
        { operator_id: MUSAN_OPERATOR_ID, provider: PROVIDER, external_vehicle_id: body.truck, vehicle_type: body.vehicle_type || null, raw_data: {} },
        'resolution=merge-duplicates,return=representation'
      );
      vehicleId = Array.isArray(vehicles) ? ((vehicles[0] && vehicles[0].id) || null) : null;
    }

    await fetch(SUPABASE_URL + '/rest/v1/routes?id=eq.' + existingRoute.id + '&operator_id=eq.' + MUSAN_OPERATOR_ID, {
      method: 'PATCH',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        driver_name: body.truck_driver || null, vehicle_id: vehicleId, status: routeStatus,
        start_time: body.started_at || null, end_time: body.ended_at || null,
        total_km: body.kpi_distance || null, raw_data: body
      })
    });

    result = Object.assign({}, result, { route_id: externalRouteId, route_status: routeStatus });
    break;
  }

  case 'dispatch_guide': {
    // Import new Paris order from DispatchTrack guide creation event
    const guide = body.dispatch_guide || {};
    const identifier = guide.identifier || guide.guide;
    if (!identifier) { result.skipped = 'no identifier in dispatch_guide'; break; }
    if (!PARIS_TENANT_CLIENT_ID) { result.skipped = 'Paris tenant_client_id not found in DB'; break; }

    await sbFetch(
      'orders?on_conflict=operator_id,order_number',
      'POST',
      {
        operator_id: MUSAN_OPERATOR_ID,
        tenant_client_id: PARIS_TENANT_CLIENT_ID,
        order_number: identifier,
        delivery_address: guide.contact_address || '',
        customer_name: guide.contact_name || '',
        customer_phone: guide.contact_phone || '',
        retailer_name: RETAILER_NAME,
        imported_via: 'API',
        delivery_date: guide.promised_date || null,
        imported_at: now.toISOString(),
        raw_data: body
      },
      'resolution=merge-duplicates,return=representation'
    );

    result = Object.assign({}, result, { order_number: identifier, tenant_client_id: PARIS_TENANT_CLIENT_ID });
    break;
  }

  case 'review':
  default:
    result.skipped = 'resource received but not processed: ' + resource;
    break;
}

return [{ json: Object.assign({}, result, { raw_body: body, upload_date: dateStr, upload_filename: filename }) }];
